request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  FILTER(CONTAINS(LCASE(STR(?modelName)), "3d0f07f9b84c4e31bbca562f472c8885") || 
         CONTAINS(LCASE(STR(?originalId)), "3d0f07f9b84c4e31bbca562f472c8885") ||
         CONTAINS(LCASE(STR(?normalizedId)), "3d0f07f9b84c4e31bbca562f472c8885"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?type ?name ?gatewayDir WHERE {
  ?elem tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3772a4c8_337f_4a64_a2fc_de2aebea6f5b> .
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
  OPTIONAL { ?elem bboExt:gatewayDirection ?gatewayDir . }
  FILTER(?type IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gatewayName ?outgoingCount WHERE {
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3772a4c8_337f_4a64_a2fc_de2aebea6f5b> .
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway bboExt:gatewayDirection "Diverging" .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  {
    SELECT ?gateway (COUNT(?edge) AS ?outgoingCount) WHERE {
      ?gateway a bboExt:ExclusiveGateway .
      ?edge a bbo:SequenceFlow .
      ?edge bbo:has_sourceRef ?gateway .
      ?edge tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3772a4c8_337f_4a64_a2fc_de2aebea6f5b> .
    }
    GROUP BY ?gateway
  }
}
ORDER BY ?gatewayName
